// Minimal local Bootstrap-like JS to handle navbar toggler and dropdowns
(function(){
  'use strict';
  // Navbar toggler (for small screens)
  function initTogglers(){
    document.querySelectorAll('.navbar-toggler').forEach(function(btn){
      btn.addEventListener('click', function(){
        var target = btn.getAttribute('data-bs-target') || btn.getAttribute('data-target');
        if(!target) return;
        var el = document.querySelector(target);
        if(!el) return;
        el.classList.toggle('show');
      });
    });
  }

  // Dropdowns
  function initDropdowns(){
    document.querySelectorAll('.nav-item.dropdown').forEach(function(dd){
      var toggle = dd.querySelector('.dropdown-toggle');
      var menu = dd.querySelector('.dropdown-menu');
      if(!toggle || !menu) return;
      toggle.addEventListener('click', function(e){
        e.preventDefault();
        var isShown = menu.classList.contains('show');
        closeAllDropdowns();
        if(!isShown) menu.classList.add('show');
      });
    });

    // close when clicking outside
    document.addEventListener('click', function(e){
      if(!e.target.closest('.nav-item.dropdown')) closeAllDropdowns();
    });

    function closeAllDropdowns(){
      document.querySelectorAll('.dropdown-menu.show').forEach(function(m){ m.classList.remove('show'); });
    }
  }

  // Init on DOM ready
  if(document.readyState==='loading'){
    document.addEventListener('DOMContentLoaded', function(){ initTogglers(); initDropdowns(); });
  } else { initTogglers(); initDropdowns(); }
})();
